// Analyze sailing conditions in 8 compass directions — delegates coord validation to shared helper
async function getDirections(c: Context) {
  return functions.call('withValidatedCoords', c, async (lat: number, lon: number) => {
    const result = await functions.call('analyzeDirections', lat, lon);

    // Map Result to HTTP response — success returns data, failure returns 500
    if (!result.ok) {
      return c.json({ error: true, message: result.error.message }, 500);
    }
    return c.json(result.data);
  }, 'Failed to analyze directions');
}

